import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.DSLFjWWy.js";const u=JSON.parse('{"title":"Routing and Replay","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/routing-and-replay.md","filePath":"concepts/routing-and-replay.md","lastUpdated":1781637126000}'),s={name:"concepts/routing-and-replay.md"};function n(d,e,i,c,h,l){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="routing-and-replay" tabindex="-1">Routing and Replay <a class="header-anchor" href="#routing-and-replay" aria-label="Permalink to &quot;Routing and Replay&quot;">​</a></h1><p>AOSC preserves document IDs and document routing during backfill and replayed index operations. Delete replay is more subtle because OpenSearch operation history does not record the routing key for deletes.</p><p>This page explains the behavior AOSC relies on when an index uses custom routing or changes shard count.</p><h2 id="opensearch-routing-basics" tabindex="-1">OpenSearch Routing Basics <a class="header-anchor" href="#opensearch-routing-basics" aria-label="Permalink to &quot;OpenSearch Routing Basics&quot;">​</a></h2><p>OpenSearch routes a document to a primary shard by hashing an effective routing value:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>effective routing = explicit _routing, when provided</span></span>\n<span class="line"><span>effective routing = _id, otherwise</span></span></code></pre></div><p>With default routing, a document ID maps to one shard. With custom routing, the same <code>_id</code> can exist on multiple shards if clients index it with different routing values. This is valid OpenSearch behavior because document identity is enforced per shard.</p><p>That distinction matters during a migration because AOSC must write transformed documents into a different target index while the source remains live.</p><h2 id="what-aosc-preserves" tabindex="-1">What AOSC Preserves <a class="header-anchor" href="#what-aosc-preserves" aria-label="Permalink to &quot;What AOSC Preserves&quot;">​</a></h2><p>Backfill reads source documents from Lucene stored fields. When a source document has routing, AOSC sends the target index request with the same routing value.</p><p>Replay reads source operation history:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Operation</th><th>Routing available to AOSC</th><th>Target behavior</th></tr></thead><tbody><tr><td>Index/create</td><td>Yes</td><td>AOSC indexes the target document with the replayed routing value.</td></tr><tr><td>Delete</td><td>No</td><td>AOSC chooses the safest delete strategy available for the source and target shard topology.</td></tr></tbody></table></div><p><code>Translog.Index</code> includes routing. <code>Translog.Delete</code> does not. This is an OpenSearch limitation rather than an AOSC-specific encoding choice. The upstream feature request is tracked in <a href="https://github.com/opensearch-project/OpenSearch/issues/20907" target="_blank" rel="noreferrer">OpenSearch issue 20907</a>.</p><h2 id="why-delete-replay-needs-a-topology" tabindex="-1">Why Delete Replay Needs a Topology <a class="header-anchor" href="#why-delete-replay-needs-a-topology" aria-label="Permalink to &quot;Why Delete Replay Needs a Topology&quot;">​</a></h2><p>OpenSearch&#39;s own replication paths avoid this problem because they operate shard-to-shard. Peer recovery, segment replication, and cross-cluster replication apply operations to a known target shard; they do not need the delete request to carry routing.</p><p>AOSC is different because it migrates into another index, possibly with a different shard count. For delete replay to be correct without the original routing key, AOSC must know which target shard or target shard group can contain documents copied from a source shard.</p><p>That is the reason the shard-count relationship matters.</p><h2 id="routing-modes" tabindex="-1">Routing Modes <a class="header-anchor" href="#routing-modes" aria-label="Permalink to &quot;Routing Modes&quot;">​</a></h2><p>AOSC detects a routing mode at migration start from the source and target index metadata.</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Source to target shards</th><th>Mode</th><th>Delete replay behavior</th><th>Custom-routed deletes</th></tr></thead><tbody><tr><td><code>N -&gt; N</code></td><td><code>SAME_SHARD</code></td><td>Deletes are sent to the corresponding target shard using a synthetic routing value for that shard.</td><td>Safe.</td></tr><tr><td><code>N -&gt; kN</code>, where <code>k</code> is a power of 2</td><td><code>SPLIT_SHARD</code></td><td>Deletes fan out to the <code>k</code> target shards that can contain documents from the source shard.</td><td>Safe. Extra fan-out deletes are no-ops.</td></tr><tr><td>Shrink, non-multiple change, or non-power-of-2 expansion</td><td><code>BULK_API</code></td><td>Deletes are sent without routing and are routed by <code>_id</code>.</td><td>Risky for custom-routed documents. Requires explicit consent.</td></tr></tbody></table></div><p>The <code>SPLIT_SHARD</code> case is restricted to power-of-2 expansion factors because that is the topology where OpenSearch&#39;s routing math keeps a bounded, non-overlapping target shard set for each source shard. A non-power-of-2 expansion can scatter documents from one source shard across target shards that overlap with other source shards.</p><p>Current implementation detail: AOSC computes synthetic routing values for the target index. In <code>SAME_SHARD</code>, a delete from source shard <code>S</code> is sent with a synthetic routing value that routes to target shard <code>S</code>. In <code>SPLIT_SHARD</code>, the delete is sent once to each target shard in the source shard&#39;s target group. Extra fan-out deletes are expected no-ops.</p><h2 id="why-bulk-api-can-lose-deletes" tabindex="-1">Why <code>BULK_API</code> Can Lose Deletes <a class="header-anchor" href="#why-bulk-api-can-lose-deletes" aria-label="Permalink to &quot;Why `BULK_API` Can Lose Deletes&quot;">​</a></h2><p>Consider a custom-routed source document:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>_id = doc-1</span></span>\n<span class="line"><span>_routing = tenant-a</span></span></code></pre></div><p>During backfill, AOSC copies it to the target with <code>_routing=tenant-a</code>.</p><p>If the source then receives a delete, OpenSearch records a <code>Translog.Delete</code> containing <code>doc-1</code>, but not <code>tenant-a</code>. In <code>BULK_API</code> mode, AOSC can only send:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DELETE /target/_doc/doc-1</span></span></code></pre></div><p>OpenSearch routes that delete by hashing <code>doc-1</code>, not <code>tenant-a</code>. If those hash to different shards, the delete is a no-op on the target and the stale document remains.</p><p>This is the main data-loss risk behind <code>accept_data_loss_if_custom_routing_is_used</code>.</p><p>There is a second edge case: a client can send a delete with the wrong routing key. OpenSearch records a delete in the shard that received the request, but the original document remains on the shard selected by its real routing key. AOSC must replay what the source shard history says; it must not search the target by <code>_id</code> and delete every matching routed copy, because that would delete data that still exists in the source.</p><h2 id="container-replicated-documents" tabindex="-1">Container-Replicated Documents <a class="header-anchor" href="#container-replicated-documents" aria-label="Permalink to &quot;Container-Replicated Documents&quot;">​</a></h2><p>Some applications intentionally write the same <code>_id</code> to multiple routing keys so the same logical document exists on multiple source shards. AOSC can preserve this only when the shard topology keeps source-shard ownership unambiguous:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Topology</th><th>Behavior</th></tr></thead><tbody><tr><td><code>SAME_SHARD</code></td><td>Each source shard copy maps to the same target shard number.</td></tr><tr><td><code>SPLIT_SHARD</code></td><td>Each source shard copy maps into that source shard&#39;s target shard group. Delete fan-out covers the group.</td></tr><tr><td><code>BULK_API</code></td><td>Copies can collide on fewer target shards, and unrouted deletes can miss stale copies.</td></tr></tbody></table></div><p>If your application depends on this pattern, avoid <code>BULK_API</code> migrations unless you have an application-specific repair or re-replication plan.</p><p><code>SPLIT_SHARD</code> preserves source-shard ownership, but it does not invent new application-level replicas. For example, if each source shard has one routed copy of a container document and you migrate from <code>N</code> to <code>2N</code> shards, AOSC preserves the <code>N</code> source copies in the correct target shard groups. It does not create <code>2N</code> routed copies. Applications that require one copy per target shard need their own re-replication or repair step after cutover.</p><p>Shard-count changes that fall back to <code>BULK_API</code> are especially risky for container-replicated documents. Two routing keys that used to land on different source shards can land on the same target shard. Since <code>_id</code> uniqueness is enforced per shard, one copy can overwrite another during backfill. Later unrouted deletes can also miss the surviving copy. This can be silent because AOSC uses idempotent index operations.</p><h2 id="consent-gate" tabindex="-1">Consent Gate <a class="header-anchor" href="#consent-gate" aria-label="Permalink to &quot;Consent Gate&quot;">​</a></h2><p>AOSC currently requires <code>options.accept_data_loss_if_custom_routing_is_used=true</code> for every <code>BULK_API</code> topology. The gate is intentionally conservative: it is based on the source and target shard relationship, not a proof that every source document uses custom routing.</p><p>Use that option only after you have checked the source write path and accepted the possibility of stale custom-routed documents in the target.</p><h2 id="practical-guidance" tabindex="-1">Practical Guidance <a class="header-anchor" href="#practical-guidance" aria-label="Permalink to &quot;Practical Guidance&quot;">​</a></h2><p>Use this decision path before changing shard count:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Source index behavior</th><th>Recommended target shard count</th></tr></thead><tbody><tr><td>Default routing only</td><td>Any target shard count that meets your operational needs; <code>BULK_API</code> still requires explicit consent for unsupported topologies.</td></tr><tr><td>Client-supplied <code>_routing</code></td><td>Prefer <code>N -&gt; N</code> or <code>N -&gt; kN</code> where <code>k</code> is a power of 2.</td></tr><tr><td>Container replication or same <code>_id</code> deliberately written with multiple routing keys</td><td>Prefer <code>N -&gt; N</code>; use <code>SPLIT_SHARD</code> only with a post-cutover plan for any application-level re-replication requirement.</td></tr><tr><td>Unknown routing behavior</td><td>Treat it as custom routing until the write path and mappings prove otherwise.</td></tr></tbody></table></div>',43)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
